import{_ as i,I as o,c as n,o as t,a5 as s,j as a,J as d,a as l}from"./chunks/framework.BtqC3pLB.js";const b=JSON.parse('{"title":"日本 -> 北海道 -> 美瑛 -> 景點 -> 白金青池","description":"","frontmatter":{},"headers":[],"relativePath":"日本/北海道/美瑛/景點/白金青池.md","filePath":"docs/日本/北海道/美瑛/景點/白金青池.md","lastUpdated":1766164770000}'),h={name:"日本/北海道/美瑛/景點/白金青池.md"};function m(g,e,p,f,u,c){const r=o("PreviewLink");return t(),n("div",null,[e[0]||(e[0]=s('<h1 id="白金青池" tabindex="-1">白金青池 <a class="header-anchor" href="#白金青池" aria-label="Permalink to “白金青池”">​</a></h1><p>白金青池位於美瑛町白金地區，是為了防止十勝岳火山噴發後的泥流災害而修築的人工堤防。因其池水呈現不可思議的鈷藍色，搭配池中枯死的落葉松，營造出極其夢幻且神祕的氛圍，因而成為全球知名的景點。</p><p><img src="https://upload.wikimedia.org/wikipedia/commons/f/ff/Shirogane_Blue_Pond_2015-09-15.jpg" alt="白金青池" loading="lazy"><em>圖片來源：Wikimedia Commons</em></p><h2 id="景點特色" tabindex="-1">景點特色 <a class="header-anchor" href="#景點特色" aria-label="Permalink to “景點特色”">​</a></h2><ul><li><strong>夢幻藍色池水：</strong> 池水的藍色是由於白金溫泉湧出的鋁離子與美瑛川水混合形成膠體，在陽光照射下產生散射現象所致。</li><li><strong>枯木景觀：</strong> 池中矗立著許多枯死的落葉松與白樺樹，與藍色池水形成強烈對比，增添了孤寂而絕美的美感。</li><li><strong>四季變換：</strong><ul><li><strong>夏季：</strong> 池水最藍，與周邊綠意相襯。</li><li><strong>秋季：</strong> 紅葉倒映在藍色水面上。</li><li><strong>冬季：</strong> 池面結冰並覆蓋白雪，夜晚有點燈活動，呈現銀白色的奇幻世界。</li></ul></li></ul><h2 id="參觀資訊" tabindex="-1">參觀資訊 <a class="header-anchor" href="#參觀資訊" aria-label="Permalink to “參觀資訊”">​</a></h2><ul><li><strong>地址：</strong> 〒071-0235 北海道上川郡美瑛町白金</li><li><strong>門票：</strong> 免費進入。</li><li><strong>停車費：</strong> 小客車 500 日圓。</li><li><strong>開放時間：</strong> 全天開放（建議白天參觀，冬季夜晚有點燈）。</li></ul><h2 id="交通手段" tabindex="-1">交通手段 <a class="header-anchor" href="#交通手段" aria-label="Permalink to “交通手段”">​</a></h2><ul><li><strong>巴士：</strong> 從 JR 美瑛站搭乘道北巴士（往白金溫泉方向）至「青池入口」站下車，步行約 5 分鐘。</li><li><strong>自駕：</strong> 從美瑛市區出發約需 20 分鐘。</li></ul><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to “相關連結”">​</a></h2>',10)),a("ul",null,[a("li",null,[d(r,{url:"https://www.biei-hokkaido.jp/zh_TW/sightseeing/shirogane-blue-pond/",placeHolderTitle:"美瑛町觀光協會 - 白金青池"})])]),e[1]||(e[1]=a("h2",{id:"溫馨提示",tabindex:"-1"},[l("溫馨提示 "),a("a",{class:"header-anchor",href:"#溫馨提示","aria-label":"Permalink to “溫馨提示”"},"​")],-1)),e[2]||(e[2]=a("ul",null,[a("li",null,"池水的藍色深淺會隨天氣、光線與降雨量而變化，晴天時色彩最為鮮豔。"),a("li",null,"冬季積雪較厚，步道可能濕滑，建議穿著防滑鞋。")],-1)),e[3]||(e[3]=a("h2",{id:"地圖",tabindex:"-1"},[l("地圖 "),a("a",{class:"header-anchor",href:"#地圖","aria-label":"Permalink to “地圖”"},"​")],-1)),e[4]||(e[4]=a("iframe",{src:"https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d2881.12!2d142.6125!3d43.4931!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x0%3A0x0!2z55m96YeR6Z2S5rGg!5e0!3m2!1szh-TW!2sjp!4v1734627200000",width:"600",height:"450",style:{border:"0"},allowfullscreen:"",loading:"lazy",referrerpolicy:"no-referrer-when-downgrade"},null,-1))])}const k=i(h,[["render",m]]);export{b as __pageData,k as default};
